import fs from 'fs-extra';
import path from 'path';
export async function generateTemplates(data) {
    const { name, stack, database, tools } = data;
    const projectDir = path.join(process.cwd(), name);
    await fs.ensureDir(projectDir);
    const createdFiles = [];
    // 1. Generate Core Orchestration
    const dockerCompose = generateDockerCompose(name, stack, database, tools);
    await writeFile(projectDir, 'docker-compose.yml', dockerCompose, createdFiles);
    const envContent = generateEnvFile(name, stack, database, tools);
    await writeFile(projectDir, '.env.example', envContent, createdFiles);
    const dockerIgnore = `node_modules\n.next\nbuild\ndist\n.git\n`;
    await writeFile(projectDir, '.dockerignore', dockerIgnore, createdFiles);
    // 2. Generate Stack Specific Files
    if (stack === 'nextjs') {
        await generateNextjsTemplate(projectDir, createdFiles);
    }
    else if (stack === 'fastapi') {
        await generateFastapiTemplate(projectDir, createdFiles);
    }
    else if (stack === 'go') {
        await generateGoTemplate(projectDir, createdFiles);
    }
    else if (stack === 'express') {
        await generateExpressTemplate(projectDir, createdFiles);
    }
    // 3. Generate README
    const readmeContent = `# ${name}\n\nStandardized environment generated by [envsetup.dev](https://envsetup.dev)\n\n## Stack\n- **Framework**: ${stack}\n- **Database**: ${database}\n- **Add-ons**: ${tools.join(', ') || 'None'}\n\n## Getting Started\n1. Run \`docker-compose up -d\`\n2. Happy coding!`;
    await writeFile(projectDir, 'README.md', readmeContent, createdFiles);
    return createdFiles;
}
async function writeFile(dir, name, content, tracker) {
    await fs.writeFile(path.join(dir, name), content);
    tracker.push(name);
}
// --- Stack Generators ---
async function generateNextjsTemplate(dir, tracker) {
    const dockerfile = `FROM node:20-alpine\nWORKDIR /app\nCOPY package*.json ./\nRUN npm install\nCOPY . .\nCMD ["npm", "run", "dev"]\n`;
    await writeFile(dir, 'Dockerfile', dockerfile, tracker);
}
async function generateFastapiTemplate(dir, tracker) {
    const dockerfile = `FROM python:3.11-slim\nWORKDIR /app\nCOPY requirements.txt .\nRUN pip install -r requirements.txt\nCOPY . .\nCMD ["uvicorn", "main:app", "--host", "0.0.0.0", "--port", "8000", "--reload"]\n`;
    await writeFile(dir, 'Dockerfile', dockerfile, tracker);
    const mainPy = `from fastapi import FastAPI\n\napp = FastAPI()\n\n@app.get("/")\ndef read_root():\n    return {"Hello": "envsetup.dev"}\n`;
    await writeFile(dir, 'main.py', mainPy, tracker);
    const reqs = `fastapi\nuvicorn\n`;
    await writeFile(dir, 'requirements.txt', reqs, tracker);
}
async function generateGoTemplate(dir, tracker) {
    const dockerfile = `FROM golang:1.21-alpine\nWORKDIR /app\nCOPY go.mod .\nRUN go mod download\nCOPY . .\nRUN go build -o main .\nCMD ["./main"]\n`;
    await writeFile(dir, 'Dockerfile', dockerfile, tracker);
    const mainGo = `package main\n\nimport "fmt"\n\nfunc main() {\n\tfmt.Println("Hello from envsetup.dev Go stack!")\n}\n`;
    await writeFile(dir, 'main.go', mainGo, tracker);
    const goMod = `module envsetup-app\n\ngo 1.21\n`;
    await writeFile(dir, 'go.mod', goMod, tracker);
}
async function generateExpressTemplate(dir, tracker) {
    const dockerfile = `FROM node:20-alpine\nWORKDIR /app\nCOPY package*.json ./\nRUN npm install\nCOPY . .\nCMD ["node", "index.js"]\n`;
    await writeFile(dir, 'Dockerfile', dockerfile, tracker);
    const indexJs = `const express = require('express');\nconst app = express();\n\napp.get('/', (req, res) => res.send('Hello from Express!'));\n\napp.listen(3000, () => console.log('Server running on port 3000'));\n`;
    await writeFile(dir, 'index.js', indexJs, tracker);
    const pkg = `{\n"name": "express-app",\n"version": "1.0.0",\n"main": "index.js",\n"dependencies": { "express": "^4.18.2" }\n}\n`;
    await writeFile(dir, 'package.json', pkg, tracker);
}
// --- Common Generators ---
function generateDockerCompose(name, stack, db, tools) {
    let services = `version: '3.8'\n\nservices:\n`;
    // App service
    services += `  app:\n    build: .\n    volumes:\n      - .:/app\n    ports:\n      - "3000:3000"\n    environment:\n      - NODE_ENV=development\n`;
    if (db === 'postgres') {
        services += `  db:\n    image: postgres:15-alpine\n    environment:\n      POSTGRES_PASSWORD: password\n    ports:\n      - "5432:5432"\n`;
    }
    else if (db === 'mongodb') {
        services += `  db:\n    image: mongo:latest\n    ports:\n      - "27017:27017"\n`;
    }
    if (tools.includes('redis')) {
        services += `  redis:\n    image: redis:alpine\n    ports:\n      - "6379:6379"\n`;
    }
    return services;
}
function generateEnvFile(name, stack, db, tools) {
    let env = `# Environment variables for ${name}\n\n`;
    env += `PROJECT_NAME=${name}\n`;
    env += `STACK=${stack}\n\n`;
    if (db === 'postgres') {
        env += `DATABASE_URL=postgresql://postgres:password@db:5432/db\n`;
    }
    else if (db === 'mongodb') {
        env += `DATABASE_URL=mongodb://db:27017/db\n`;
    }
    if (tools.includes('redis')) {
        env += `REDIS_URL=redis://redis:6379\n`;
    }
    return env;
}
